import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"87. Occupational Health And Safety Workplace Violence","description":"","frontmatter":{"title":"87. Occupational Health And Safety Workplace Violence","eba":"Biomedical Engineers 2025-2028","topics":["consultation"]},"headers":[],"relativePath":"ebas/biomedical-engineers/workplace-rights/87-occupational-health-and-safety-workplace-violence.md","filePath":"ebas/biomedical-engineers/workplace-rights/87-occupational-health-and-safety-workplace-violence.md"}'),r={name:"ebas/biomedical-engineers/workplace-rights/87-occupational-health-and-safety-workplace-violence.md"};function a(s,e,p,l,c,g){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_87-occupational-health-and-safety-workplace-violence" tabindex="-1">87. Occupational Health And Safety Workplace Violence <a class="header-anchor" href="#_87-occupational-health-and-safety-workplace-violence" aria-label="Permalink to &quot;87. Occupational Health And Safety Workplace Violence&quot;">​</a></h1><p><strong>87.1</strong> OHS Risk Management</p><p><strong>(a)</strong> Those covered by this Agreement will take a pro-active approach to the prevention and management of workplace injuries, and to the achievement of a reduction in workplace injuries through the implementation of risk management systems incorporating hazard identification, risk assessment and control, and safe work practices.</p><p><strong>(b)</strong> The Employer recognises that its obligations to provide a safe workplace, extend to the places and localities it directs Employees to perform work.</p><p><strong>(c)</strong> Those covered by this Agreement recognise that consultation with Employees and their representatives is crucial to achieving a healthy and safe work environment. To this end, Employers will consult Employees and their representatives around matters relating to health and safety in the workplace.</p><p><strong>(d)</strong> The Employer will implement the hierarchy of controls to control hazards and will eliminate the hazard at the source wherever practicable.</p><p><strong>(e)</strong> This Agreement recognises that hazards include, but are not limited to:</p><p><strong>(i)</strong> repetitive stress;</p><p><strong>(ii)</strong> occupational violence and aggression;</p><p><strong>(iii)</strong> circumstances that give rise to adverse effects on psychological health, including aggression or violence, bullying or sexual harassment.</p><p><strong>(iv)</strong> unsafe design and layout of workplaces;</p><p><strong>(v)</strong> slips, trips and falls;</p><p><strong>(vi)</strong> electrocution; and,</p><p><strong>(vii)</strong> blood borne and other infectious diseases.</p><p><strong>(f)</strong> The Employer will ensure that people in management positions will receive adequate education and support to ensure the following can occur:</p><p><strong>(i)</strong> identification and the assessment of OHS risks;</p><p><strong>(ii)</strong> the undertaking of OHS incident investigations; and</p><p><strong>(iii)</strong> consultation with Employees over OHS issues.</p><p><strong>(g)</strong> The Employer will provide such information, education, training and supervision to all Employees of the Employer required to enable them to perform their work in a manner which is safe and without risks to physical and psychological health. This will occur on a regular basis as required to enable Employees to remain informed in relation to health and safety hazards, policies and procedures.</p><p><strong>87.2</strong> Incident Reporting, Investigation and Prevention</p><p><strong>(a)</strong> The Employer will facilitate timely reporting of incidents by Employees, and ensure Employees who report incidents are appropriately supported.</p><p><strong>(b)</strong> Following an incident, the Employer will as soon as practicable:</p><p><strong>(i)</strong> provide the Employee(s) with access to post incident support services;</p><p><strong>(ii)</strong> take appropriate action to prevent further injury to Employees;</p><p><strong>(iii)</strong> conduct an incident investigation in a timely manner and implement workplace controls to prevent the incident recurring; and</p><p><strong>(iv)</strong> provide information regarding the Employee’s rights as relevant including the making and lodging of a workers compensation claim or reporting to police.</p><p><strong>(c)</strong> The Employer will provide information, instruction and training to Employees and management staff regarding the importance of timely reporting, procedures regarding incident reporting, and linking this to incident investigation and prevention.</p><p><strong>87.3</strong> HSR Training</p><p><strong>(a)</strong> HSRs will be entitled and encouraged to attend a WorkSafe Victoria approved course as soon as practicable following their election.</p><p><strong>(b)</strong> The Employer will permit HSRs to take such time as is necessary or prescribed to attend occupational health and safety training courses approved by WorkSafe Victoria.</p><p><strong>(c)</strong> HSRs will have the right to choose which course to attend, provided it is a WorkSafe Victoria approved course. An Employer will not prevent or obstruct an HSR from attending a course chosen by them.</p><p><strong>(d)</strong> When attending an approved course, HSRs will be paid as if the HSR had been at work.</p><p><strong>(e)</strong> Where HSRs attend an approved course outside their normal working hours or roster, they will be paid as if they had been at work for the relevant time.</p><p><strong>(f)</strong> The Employer is responsible for payment of course fees, travel costs and accommodation for HSR attendance at WorkSafe Victoria approved courses.</p><p><strong>87.4</strong> Facilities for HSRs</p><p><strong>(a)</strong> HSRs will be provided with reasonable access to an office, telephone, computer (including email facilities where available), notice board, meeting room, and such other facilities as are necessary to enable them to perform their functions or duties as prescribed under the OHS Act.</p><p><strong>(b)</strong> HSRs will have reasonable time release from duty to perform their functions and duties as is necessary or prescribed under the OHS Act.</p><p><strong>(c)</strong> A Health and Safety Committee will be established where requested by a HSR.</p><p><strong>87.5</strong> Employee support and debriefing</p><p><strong>(a)</strong> The Employer will provide support and debriefing to Employees who have directly or vicariously experienced a “critical incident” during the course of the work that results in personal distress or psychological trauma. The Employer is committed to assisting the recovery of Employees experiencing distress or trauma following a critical incident within the workplace with the aim of returning Employees to their pre-incident level of functioning as soon as possible.</p><p><strong>(b)</strong> A critical incident is defined as an event outside the range of usual human experience within the workplace which has the potential to easily overcome a person&#39;s normal ability to cope with stress. It may produce a negative psychological response in an Employee who was involved in or witnessed, or otherwise deals with and/or is exposed through their course of their duties to the details of such an incident.</p><p><strong>(c)</strong> Critical incidents in the workplace environment include, but are not limited to:</p><p><strong>(i)</strong> violent assaults; or</p><p><strong>(ii)</strong> suicide or attempted suicide; or</p><p><strong>(iii)</strong> sudden or unexpected death; or</p><p><strong>(iv)</strong> hostage or siege situations; or</p><p><strong>(v)</strong> threats to kill; or</p><p><strong>(vi)</strong> accounts of sexual violence; or</p><p><strong>(vii)</strong> accounts of child abuse and domestic violence;</p><p><strong>(viii)</strong> any other serious accidents or incidents.</p><p><strong>87.6</strong> Occupational Violence and Aggression Prevention and Management</p><p><strong>(a)</strong> Employees are entitled to be provided a workplace free of occupational violence and aggression.</p><p><strong>(b)</strong> The parties to the Agreement support action to end violence and aggression in workplaces.</p><p><strong>(c)</strong> Occupational Violence and Aggression Prevention Action Plan</p><p><strong>(i)</strong> The Employer will develop an action plan, which will be subject to ongoing review, to address occupational violence and aggression.</p><p><strong>(ii)</strong> Any action plan will: <strong>(A)</strong> implement proactive measures to identify and address risks; <strong>(B)</strong> ensure a reporting culture and mechanisms to assist in investigation; and <strong>(C)</strong> provide appropriate support following workplace incidents.</p><p><strong>(iii)</strong> The action plan will be consistent with the WorkSafe Guidance note relevant to occupational violence and aggression.</p><p><strong>(iv)</strong> In developing or reviewing an action plan the Employer will consult with HSRs, the Union and affected Employees to identify any gaps having regard for the requirements at (ii)87.6(c)(ii).</p><p><strong>(v)</strong> The Employer will designate an occupational health and safety committee (which may be an existing committee) as responsible for overseeing the actions required by this clause.</p><p><strong>(vi)</strong> Nothing in this clause limits an Employer from doing anything to support the reduction and prevention of occupational violence and aggression.</p><p><strong>(d)</strong> Key Principles In developing, reviewing and implementing any policies, the following matters will be considered:</p><p><strong>(i)</strong> security;</p><p><strong>(ii)</strong> risk identification;</p><p><strong>(iii)</strong> incident reporting, investigation and action;</p><p><strong>(iv)</strong> workplace design;</p><p><strong>(v)</strong> training;</p><p><strong>(vi)</strong> integration of policies and procedures;</p><p><strong>(vii)</strong> post incident support;</p><p><strong>(viii)</strong> application across all health disciplines;</p><p><strong>(ix)</strong> empowering staff to expect a safe workplace.</p><p><strong>(e)</strong> Continuous Improvement The Employer will undertake annual audits of their occupational violence and aggression management strategy, in consultation with HSRs.</p>',71)])])}const u=t(r,[["render",a]]);export{h as __pageData,u as default};
